    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'Morning Mobility - 1w 7x/wk',
    'flexibility',
    7,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Morning Mobility'
ON CONFLICT DO NOTHING;

